mapper.insert:
INSERT INTO payment_pass (
pay_no,
pass_no,
item_name
)
VALUES (
#{payNo},
#{passNo},
#{itemName}
)

mapper.select:
SELECT COUNT(*)
FROM user_pass_wallet
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO user_pass_wallet (
user_id, remaining_count, total_purchased, pass_no
)
VALUES (
#{userId},
#{reviewCnt},
#{reviewCnt},
#{passNo}
)

mapper.update:
UPDATE user_pass_wallet
SET
remaining_count = remaining_count + #{reviewCnt},
total_purchased = total_purchased + #{reviewCnt},
pass_no = #{passNo}
WHERE user_id = #{userId}

mapper.insert:
INSERT INTO payment_resistration (
pay_no,
company_no
)
VALUES (
#{payNo},
#{companyNo}
)
